package main

import (
	"math"
	"sort"
)

func solve(m int64, n int64, waitCost [][]int64) int64 {
	mInt := int(m)
	nInt := int(n)
	dist := make([][]int64, mInt)
	for i := 0; i < mInt; i++ {
		dist[i] = make([][]int64, nInt)
		for j := 0; j < nInt; j++ {
			dist[i][j] = make([]int64, 2)
			for k := 0; k < 2; k++ {
				dist[i][j][k] = math.MaxInt64
			}
		}
	}

	initialCost := (0 + 1) * (0 + 1)
	dist[0][0][1] = initialCost

	pq := [][]int64{
		{initialCost, 0, 0, 1},
	}

	for len(pq) > 0 {
		sort.Slice(pq, func(i, j int) bool {
			return pq[i][0] < pq[j][0]
		})
		current := pq[0]
		pq = pq[1:]

		cost := current[0]
		i := current[1]
		j := current[2]
		parity := current[3]

		if i == int(m)-1 && j == int(n)-1 {
			return cost
		}

		if cost > dist[i][j][parity] {
			continue
		}

		if parity == 1 {
			if j+1 < nInt {
				ni, nj := i, j+1
				newCost := cost + (ni+1)*(nj+1)
				if newCost < dist[ni][nj][0] {
					dist[ni][nj][0] = newCost
					pq = append(pq, []int64{newCost, ni, nj, 0})
				}
			}
			if i+1 < mInt {
				ni, nj := i+1, j
				newCost := cost + (ni+1)*(nj+1)
				if newCost < dist[ni][nj][0] {
					dist[ni][nj][0] = newCost
					pq = append(pq, []int64{newCost, ni, nj, 0})
				}
			}
		} else {
			newCost := cost + int64(waitCost[i][j])
			if newCost < dist[i][j][1] {
				dist[i][j][1] = newCost
				pq = append(pq, []int64{newCost, i, j, 1})
			}
		}
	}

	return -1
}
